import { Injectable, signal, computed } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Router } from '@angular/router';
import { Observable, tap } from 'rxjs';
import { environment } from '../../../environments/environment';
import { AuthResponse, Role, User } from '../models';

const TOKEN_KEY = 'token';
const ACCESS_KEY = 'access_token';
const USER_KEY = 'user';
const AUTH_FLAG = 'isAuthenticated';

function readUser(): User | null {
  try {
    const raw = localStorage.getItem(USER_KEY);
    return raw ? (JSON.parse(raw) as User) : null;
  } catch {
    return null;
  }
}

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly apiUrl = environment.apiUrl;

  private _user = signal<User | null>(readUser());
  readonly user = this._user.asReadonly();
  readonly isLoggedIn = computed(() => !!this._user());
  readonly role = computed<Role | null>(() => this._user()?.role ?? null);
  readonly isManager = computed(() => this._user()?.role === 'manager');

  constructor(private http: HttpClient, private router: Router) {}

  login(email: string, password: string): Observable<AuthResponse> {
    return this.http
      .post<AuthResponse>(`${this.apiUrl}/auth/login`, { email, password })
      .pipe(tap((res) => this.persist(res)));
  }

  signup(name: string, email: string, password: string): Observable<AuthResponse> {
    return this.http
      .post<AuthResponse>(`${this.apiUrl}/auth/signup`, { name, email, password })
      .pipe(tap((res) => this.persist(res)));
  }

  private persist(res: AuthResponse): void {
    const token = res.access_token || res.token || '';
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(ACCESS_KEY, token);
    localStorage.setItem(USER_KEY, JSON.stringify(res.user));
    localStorage.setItem(AUTH_FLAG, 'true');
    this._user.set(res.user);
  }

  /** Demo Mode — bypass the backend so reviewers can inspect the authenticated UI. */
  demoLogin(role: Role = 'manager'): void {
    const user: User =
      role === 'manager'
        ? { id: 'demo-manager', email: 'manager@demo', name: 'Demo Manager', role: 'manager' }
        : { id: 'demo-tenant', email: 'tenant1@demo', name: 'Demo Tenant', role: 'tenant' };
    const token = 'demo-token';
    localStorage.setItem(TOKEN_KEY, token);
    localStorage.setItem(ACCESS_KEY, token);
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    localStorage.setItem(AUTH_FLAG, 'true');
    this._user.set(user);
    this.router.navigate([role === 'manager' ? '/dashboard' : '/my-lease']);
  }

  logout(): void {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(ACCESS_KEY);
    localStorage.removeItem(USER_KEY);
    localStorage.removeItem(AUTH_FLAG);
    this._user.set(null);
    this.router.navigate(['/login']);
  }

  token(): string | null {
    return localStorage.getItem(TOKEN_KEY);
  }
}
